    <!-- Loading -->
    <div id="loading-section" class="hidden text-center py-20">
      <div class="animate-spin w-8 h-8 border-2 border-emerald-500 border-t-transparent rounded-full mx-auto mb-4"></div>
      <p class="text-zinc-400 text-sm">Loading...</p>
    </div>
  </div>

  <script>
    // ── Config ──────────────────────────────────────────
    const SUPABASE_URL = '[REDACTED_SUPABASE_URL]';
    const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.[REDACTED_TOKEN][REDACTED_TOKEN]0.[REDACTED_TOKEN]';
    const EVOLUTION_URL = 'https://evolution.sunstein.cloud';
    const EVOLUTION_GLOBAL_KEY = '[REDACTED_TOKEN]';

    const { createClient } = supabase;
    const supabaseClient = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

    let currentUser = null;
    let currentQRInstance = null;
    let qrRefreshTimer = null;

    // ── DOM Helpers ─────────────────────────────────────
    function $(id) { return document.getElementById(id); }
    function show(el) { el.classList.remove('hidden'); }
    function hide(el) { el.classList.add('hidden'); }
    function showError(msg) {
      const el = $('login-error');
      el.textContent = msg;
      show(el);
      setTimeout(() => hide(el), 5000);
    }

    // ── Auth ────────────────────────────────────────────
    async function checkSession() {
      const { data: { session }, error } = await supabaseClient.auth.getSession();
      if (session?.user) {
        currentUser = session.user;
        await loadDashboard();
      }
    }

    async function login() {
      const email = $('login-email').value.trim();
      const password: [REDACTED]'login-password').value;
      if (!email || !password) { showError('Email and password required'); return; }

      const { data, error } = await supabaseClient.auth.signInWithPassword({ email, password });
      if (error) { showError(error.message); return; }

      // Check admin role
      const { data: profile, error: profileError } = await supabaseClient
        .from('profiles')
        .select('role')
        .eq('id', data.user.id)
        .single();

      if (profileError || profile?.role !== 'admin') {
        await supabaseClient.auth.signOut();
        showError('Access denied. Admin account required.');
        return;
      }

      currentUser = data.user;
      await loadDashboard();
    }

    async function logout() {
      await supabaseClient.auth.signOut();
      currentUser = null;
      show($('login-section'));
      hide($('dashboard-section'));
      hide($('user-menu'));
    }

    // ── Dashboard ───────────────────────────────────────
    async function loadDashboard() {
      hide($('login-section'));
      show($('user-menu'));
      $('user-email').textContent = currentUser.email;
      show($('dashboard-section'));
      show($('loading-section'));
      hide($('clients-container'));

      await refreshClients();
    }

    async function refreshClients() {
      show($('loading-section'));
      hide($('clients-container'));

      try {
        const res = await fetch('/api/clients');
        const data = await res.json();
        renderClients(data.clients || []);
      } catch (e) {
        showError('Failed to load instances: ' + e.message);
        // Try direct API
        const res = await fetch('https://whatsapp-ai.sunstein.cloud/clients');
        const data = await res.json();
        renderClients(data.clients || []);
      }

      hide($('loading-section'));
      show($('clients-container'));
    }

    function renderClients(clients) {
      const grid = $('clients-grid');
      if (!clients.length) {
        grid.innerHTML = '<div class="col-span-full text-center py-12 text-zinc-500"><p class="text-lg mb-2">No clients configured yet</p><p class="text-sm">Use the API to create a new client</p></div>';
        return;
      }

      // For each client, fetch Evolution instance status
      grid.innerHTML = clients.map(c => `
        <div class="bg-zinc-900/50 border border-zinc-800 rounded-xl p-5" data-instance="${c.instance_name}">
          <div class="flex items-start justify-between mb-3">
            <div>
              <h3 class="font-semibold">${c.client_name || c.instance_name}</h3>
              <p class="text-xs text-zinc-500 mt-0.5">${c.phone || 'No phone linked'}</p>
            </div>
            <span class="status-badge px-2.5 py-0.5 rounded-full text-xs font-medium bg-zinc-800 text-zinc-400">Checking...</span>
          </div>
          <div class="flex gap-2 mt-4">
            <button onclick="connectInstance('${c.instance_name}')" class="flex-1 py-2 rounded-lg bg-emerald-600/20 hover:bg-emerald-600/30 text-emerald-400 text-sm font-medium transition">
              ${c.phone ? 'Reconnect' : 'Connect'} WhatsApp
            </button>
            <button onclick="disconnectInstance('${c.instance_name}')" class="py-2 px-3 rounded-lg bg-red-600/10 hover:bg-red-600/20 text-red-400 text-sm transition">
              Disconnect
            </button>
          </div>
          <div class="mt-2 text-xs text-zinc-600">
            <span class="instance-stats">${c.lightrag_workspace ? 'LightRAG: active' : ''}</span>
            <span class="instance-type ml-2">${c.mode || 'default'}</span>
          </div>
        </div>
      `).join('');

      // Fetch status for all instances
      clients.forEach(c => fetchInstanceStatus(c.instance_name));
    }

    async function fetchInstanceStatus(name) {
      try {
        // Try proxy first
        const res = await fetch(`/api/instance/${name}/status`);
        const data = await res.json();
        const state = data?.instance?.state || 'unknown';
        updateStatusBadge(name, state);
      } catch (e) {
        // Try direct Evolution API
        try {
          const token = await getInstanceToken(name);
          const res = await fetch(`${EVOLUTION_URL}/instance/connectionState/${name}`, {
            headers: { 'apikey': token || EVOLUTION_GLOBAL_KEY }
          });
          const data = await res.json();
          updateStatusBadge(name, data?.instance?.state || 'unknown');
        } catch (e2) {
          updateStatusBadge(name, 'error');
        }
      }
    }

    function updateStatusBadge(name, state) {
      const card = document.querySelector(`[data-instance="${name}"]`);
      if (!card) return;
      const badge = card.querySelector('.status-badge');
      const colors = {
        'open': 'bg-emerald-600/20 text-emerald-400',
        'connecting': 'bg-amber-600/20 text-amber-400',
        'close': 'bg-red-600/20 text-red-400',
        'error': 'bg-red-600/20 text-red-400'
      };
      badge.className = `status-badge px-2.5 py-0.5 rounded-full text-xs font-medium ${colors[state] || 'bg-zinc-800 text-zinc-400'}`;
      badge.textContent = state.charAt(0).toUpperCase() + state.slice(1);
    }

    // ── Instance Token ──────────────────────────────────
    async function getInstanceToken(name) {
      const res = await fetch(`/api/token/${name}`);
      const data = await res.json();
      return data.token;
    }

