const fs = require('fs');
const path = require('path');
const { URL } = require('url');

const PORT = 8990;
const PUBLIC_DIR = path.join(__dirname, 'public');
const EVOLUTION_URL = 'https://evolution.sunstein.cloud';
const EVOLUTION_API_KEY = process.env.EVOLUTION_API_KEY || '[REDACTED_TOKEN]';
const PG_DSN = process.env.PG_DSN;
const API_BASE = process.env.API_BASE || 'https://whatsapp-ai.sunstein.cloud';

// ── MIME Types ──────────────────────────────────────
const MIME = {
  '.html': 'text/html; charset=utf-8',
  '.js': 'application/javascript',
  '.css': 'text/css',
  '.png': 'image/png',
  '.svg': 'image/svg+xml',
  '.json': 'application/json',
};

// ── Serve Static ────────────────────────────────────
function serveStatic(req, res) {
  let filePath = path.join(PUBLIC_DIR, req.url === '/' ? 'index.html' : req.url);
  if (!fs.existsSync(filePath)) {
    filePath = path.join(PUBLIC_DIR, 'index.html');
  }
  const ext = path.extname(filePath);
  const mimeType = MIME[ext] || 'application/octet-stream';

  fs.readFile(filePath, (err, data) => {
    if (err) {
      res.writeHead(500);
      res.end('500 Internal Server Error');
      return;
    }
    res.writeHead(200, { 'Content-Type': mimeType });
    res.end(data);
  });
}

// ── API Proxy ────────────────────────────────────────
async function proxyRequest(req, res) {
  const url = new URL(req.url, `http://localhost:${PORT}`);
  const pathParts = url.pathname.split('/').filter(Boolean);
  const method = req.method;

  res.setHeader('Content-Type', 'application/json');

  try {
    // GET /api/clients — list all clients from WhatsApp AI API
    if (pathParts[0] === 'api' && pathParts[1] === 'clients' && !pathParts[2]) {
      const apiRes = await fetch(`${API_BASE}/clients`);
      const data = await apiRes.json();
      res.writeHead(200);
      res.end(JSON.stringify(data));
      return;
    }

    // GET /api/token/:instance — get instance token from Evolution DB via WhatsApp AI API
    if (pathParts[0] === 'api' && pathParts[1] === 'token' && pathParts[2]) {
      const instanceName = pathParts[2];
      const apiRes = await fetch(`${API_BASE}/clients/${instanceName}`);
      const data = await apiRes.json();
      res.writeHead(200);
      res.end(JSON.stringify(data));
      return;
    }

    // GET /api/instance/:name/status
    if (pathParts[0] === 'api' && pathParts[1] === 'instance' && pathParts[2] && pathParts[3] === 'status') {
      const instanceName = pathParts[2];
      // Use instance token from Evolution DB
      try {
        const tokenRes = await fetch(`${API_BASE}/clients/${instanceName}`);
        const tokenData = await tokenRes.json();
        const token = tokenData.token || EVOLUTION_API_KEY;
        const evoRes = await fetch(`${EVOLUTION_URL}/instance/connectionState/${instanceName}`, {
          headers: { 'apikey': token }
        });
        const data = await evoRes.json();
        res.writeHead(200);
        res.end(JSON.stringify(data));
      } catch (e) {
        // Fallback: use global key
        const evoRes = await fetch(`${EVOLUTION_URL}/instance/connectionState/${instanceName}`, {
          headers: { 'apikey': EVOLUTION_API_KEY }
        });
        const data = await evoRes.json();
        res.writeHead(200);
        res.end(JSON.stringify(data));
      }
      return;
    }

    // Not found
    res.writeHead(404);
    res.end(JSON.stringify({ error: 'Not found' }));

  } catch (e) {
    console.error('Proxy error:', e.message);
    res.writeHead(502);
    res.end(JSON.stringify({ error: e.message }));
  }
}

// ── Server ───────────────────────────────────────────
const server = http.createServer((req, res) => {
  if (req.url.startsWith('/api/')) {
    proxyRequest(req, res);
  } else {
    serveStatic(req, res);
  }
});

server.listen(PORT, '0.0.0.0', () => {
  console.log(`WhatsApp Connect server running on http://0.0.0.0:${PORT}`);
});
